12	const ciBaseUrl = "http://localhost:3210";
13	const localBaseUrl = "http://localhost:3210";
14	const baseUrl = process.env.CI ? ciBaseUrl : localBaseUrl;
15	const readinessUrl = `${baseUrl}/robots.txt`;
16	const webServerEnv = Object.fromEntries(
17	  Object.entries(process.env).filter(
18	    (entry): entry is [string, string] => entry[1] !== undefined,
19	  ),
20	);
21	
22	/**
23	 * See https://playwright.dev/docs/test-configuration.
24	 */
25	export default defineConfig({
26	  timeout: process.env.CI ? 20_000 : 5_000,
27	  testDir: testsRoot,
28	  fullyParallel: true,
29	  retries: 0,
30	  workers: process.env.CI ? 8 : 5,
31	  reporter: [
32	    ["html", { outputFolder: path.join(configDirectory, "playwright-report") }],
33	  ],
34	  expect: {
35	    timeout: process.env.CI ? 10_000 : 5_000,
36	  },
37	  use: {
38	    baseURL: baseUrl,
39	    trace: "off",
40	    video: "retain-on-failure",
41	  },
42	  projects: [{ name: "chromium", use: { ...devices["Desktop Chrome"] } }],
43	  webServer: {
44	    command: process.env.CI
45	      ? "pnpm exec vite build --mode test && pnpm exec vite preview --port 3210"
46	      : "pnpm exec vite dev --port 3210 --mode test",
47	    env: webServerEnv,
48	    url: readinessUrl,
49	    reuseExistingServer: !process.env.CI,
50	    stdout: "pipe",
51	    stderr: "pipe",
52	  },
53	});
