4	const loadAuthedRouteFn = createServerFn({ method: "GET" }).handler(
5	  async () => {
6	    const { getAppBootstrapData } = await import("../server/app-bootstrap");
7	    const { OrgApiError } = await import("../server/error");
8	
9	    try {
10	      const appBootstrap = await getAppBootstrapData();
11	
12	      if (!appBootstrap) {
13	        throw redirect({ to: "/login" });
14	      }
15	
16	      return appBootstrap;
17	    } catch (error) {
18	      if (error instanceof OrgApiError && error.status === 401) {
19	        throw redirect({ to: "/login" });
20	      }
21	
22	      throw error;
23	    }
24	  },
25	);
26	
27	export const Route = createFileRoute("/_authed")({
28	  loader: async ({ location }) => {
29	    const appBootstrap = await loadAuthedRouteFn();
30	
31	    const onWorkspaceNewRoute =
32	      location.pathname === "/workspace/new" ||
33	      location.pathname.endsWith("/workspace/new");
34	
35	    if (appBootstrap.user && !appBootstrap.tenant && !onWorkspaceNewRoute) {
36	      throw redirect({ to: "/workspace/new" });
37	    }
38	
39	    return appBootstrap;
40	  },
41	  component: AuthedLayout,
42	});
