1	import type { AppBootstrap, Tenant, User } from "../types/bootstrap";
2	import { OrgApiError } from "./error";
3	import { getOrgApiJson } from "./org-api.server";
4	import { resolveOrgApiAccessToken } from "./org-api-access-token.server";
5	
6	const pickCurrentTenant = (accessibleTenants: Tenant[], tenantId?: number) => {
7	  if (tenantId === undefined) {
8	    return accessibleTenants[0] ?? null;
9	  }
10	
11	  return accessibleTenants.find((tenant) => tenant.id === tenantId) ?? null;
12	};
13	
14	const buildAppBootstrap = ({
15	  accessibleTenants,
16	  tenantId,
17	  user,
18	}: {
19	  accessibleTenants: Tenant[];
20	  tenantId?: number;
21	  user: User;
22	}): AppBootstrap => {
23	  const currentTenant = pickCurrentTenant(accessibleTenants, tenantId);
24	
25	  return {
26	    accessibleTenants,
27	    currentTenant,
28	    currentUser: user,
29	    tenant: currentTenant,
30	    tenants: accessibleTenants,
31	    user,
32	    users: [user],
33	  };
34	};
35	
36	async function fetchCurrentUser(): Promise<User | null> {
37	  let user: User;
38	
39	  try {
40	    user = await getOrgApiJson<User>("/users/me");
41	    return user;
42	  } catch (error) {
43	    if (error instanceof OrgApiError && error.status === 404) {
44	      return null;
45	    }
46	
47	    throw error;
48	  }
49	}
50	
51	async function fetchAccessibleTenants(): Promise<Tenant[]> {
52	  try {
53	    return await getOrgApiJson<Tenant[]>("/tenants");
54	  } catch (error) {
55	    if (error instanceof OrgApiError && error.status === 401) {
56	      throw error;
57	    }
58	
59	    return [];
60	  }
61	}
62	
63	export async function getAppBootstrapData({
64	  tenantId,
65	}: {
66	  tenantId?: number;
67	} = {}): Promise<AppBootstrap | null> {
68	  const accessToken = await resolveOrgApiAccessToken();
69	
70	  if (accessToken === null) {
71	    return null;
72	  }
73	
74	  const user = await fetchCurrentUser();
75	  if (user === null) {
76	    return null;
77	  }
78	  const accessibleTenants = await fetchAccessibleTenants();
79	
80	  return buildAppBootstrap({
81	    accessibleTenants,
82	    tenantId,
83	    user,
84	  });
85	}
